/**
 * Format Amount Utility
 * 
 * Provides consistent currency formatting across the application.
 * All amounts are displayed with exactly 2 decimal places.
 */

/**
 * Format a number as a currency amount with 2 decimal places
 * @param {number|string} value - The amount to format
 * @param {boolean} includeCommas - Whether to include thousand separators (default: true)
 * @returns {string} - Formatted amount (e.g., "1,234.00")
 */
export const formatAmount = (value, includeCommas = true) => {
    // Handle null, undefined, or empty values
    if (value === null || value === undefined || value === '') {
        return '0.00';
    }

    // Convert to number
    const numValue = typeof value === 'string' ? parseFloat(value) : value;

    // Handle NaN
    if (isNaN(numValue)) {
        return '0.00';
    }

    // Format with 2 decimal places
    const formatted = numValue.toFixed(2);

    // Add thousand separators if requested
    if (includeCommas) {
        const parts = formatted.split('.');
        parts[0] = parts[0].replace(/\B(?=(\d{3})+(?!\d))/g, ',');
        return parts.join('.');
    }

    return formatted;
};

/**
 * Format amount with currency symbol
 * @param {number|string} value - The amount to format
 * @param {string} currency - Currency code (default: 'GHS')
 * @param {boolean} includeCommas - Whether to include thousand separators (default: true)
 * @returns {string} - Formatted amount with currency (e.g., "GHS 1,234.00")
 */
export const formatCurrencyAmount = (value, currency = 'GHS', includeCommas = true) => {
    const formattedValue = formatAmount(value, includeCommas);
    return `${currency} ${formattedValue}`;
};
