/**
 * Payment Provider Redirect Whitelist
 * 
 * Defines allowed domains for payment provider redirects.
 * All payment redirects are validated against this whitelist to prevent
 * phishing attacks and malicious redirects from compromised backends.
 * 
 * Only URLs matching these domains will be allowed to open in new windows.
 */

export const PAYMENT_REDIRECT_WHITELIST = [
  // iSmartPay Collection Service (Wallet Top-up, Invoicing, Bank Collection)
  'https://dev.collection.ismartghana.com',
  'https://collection.ismartghana.com',
  'https://collections.ismartghana.com',
  
  // iSmartPay Payment Portal
  'https://payportal.ismartghana.com',
  'https://payment.ismartghana.com',
  'https://payments.ismartghana.com',
  
  // iSmartPay Gateway (Disbursement & Settlement)
  'https://gateway.ismartghana.com',
  
  // iSmartGhana Main Domain (catch-all for any ismartghana.com subdomain)
  'https://ismartghana.com',
  
  // Third-party Payment Processors
  'https://calpay.caleservice.net',
  
  // Development/Testing (only in dev environment)
  ...(import.meta.env.DEV ? [
    'http://localhost:3000',
    'http://localhost:5173',
    'http://localhost:8080',
    'http://127.0.0.1:3000',
  ] : []),
];

/**
 * Validates if a URL is allowed for external redirect
 * Allows any subdomain of ismartghana.com and whitelisted payment processors
 * @param {string} url - The URL to validate
 * @returns {boolean} True if URL matches whitelist, false otherwise
 */
export const isAllowedPaymentRedirect = (url) => {
  if (!url || typeof url !== 'string') {
    return false;
  }

  try {
    // Parse the URL to extract hostname
    const urlObj = new URL(url);
    
    // Allow any *.ismartghana.com subdomain or exactly ismartghana.com
    // This is secure because we own the ismartghana.com domain
    if (urlObj.hostname === 'ismartghana.com' || urlObj.hostname.endsWith('.ismartghana.com')) {
      return true;
    }
    
    // Check explicit whitelist for third-party payment processors and localhost
    return PAYMENT_REDIRECT_WHITELIST.some(whitelistedDomain => {
      try {
        const whitelistObj = new URL(whitelistedDomain);
        // Exact hostname match
        return urlObj.hostname === whitelistObj.hostname;
      } catch {
        return false;
      }
    });
  } catch (error) {
    // Invalid URL format
    return false;
  }
};

/**
 * Safely opens a payment redirect URL
 * Validates URL against whitelist before opening to prevent phishing
 * @param {string} url - The URL to open
 * @param {Function} onError - Error callback if URL is not allowed
 * @returns {boolean} True if opened successfully, false if blocked
 */
export const safePaymentRedirect = (url, onError) => {
  if (!isAllowedPaymentRedirect(url)) {
    const error = new Error(`Payment redirect to unauthorized domain blocked: ${url}`);
    if (onError) {
      onError(error);
    }
    return false;
  }

  try {
    // Open in new window with security flags
    // noopener: Prevents new window from accessing window.opener
    // noreferrer: Doesn't send Referer header (already handled by Referrer-Policy)
    window.open(url, '_blank', 'noopener,noreferrer');
    return true;
  } catch (error) {
    if (onError) {
      onError(error);
    }
    return false;
  }
};
